**Idea:**

Sort the array of strings. Once sorted, the first and last strings will be the most dissimilar in the array. Thus, the longest common prefix for the entire list must be the common prefix between these two strings.

**Steps:**


Sort the list of strings.
Compare the characters of the first and last string until the characters differ.
The substring from the beginning up to the point of difference is the longest common prefix.
If no common characters are found, output −1-1−1.
**Complexity:**


Sorting takes approximately O(nlog⁡n)O(n \log n)O(nlogn) (with nnn strings), and comparing the first and last strings takes O(m)O(m)O(m), where mmm is the length of the shortest string among the two.
**Example:**

For the input `["flower", "flow", "flight"]`, sorting gives `["flight", "flow", "flower"]`. Comparing `"flight"` and `"flower"` yields `"fl"` as the common prefix.

**C++ Implementation:**

`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;
using namespace std;

string findPrefix(vector&lt;string&gt;&amp; str) {
    sort(str.begin(), str.end());
    string ans = "";
    int n = str.size();
    string first = str[0], last = str[n - 1];
    for (int i = 0; i &lt; min(first.size(), last.size()); i++) {
        if (first[i] != last[i]) {
            return ans.empty() ? "-1" : ans;
        }
        ans += first[i];
    }
    return ans.empty() ? "-1" : ans;
}

int main() {
    int t;
    cin &gt;&gt; t;
    while (t--) {
        int n;
        cin &gt;&gt; n;
        vector&lt;string&gt; str(n);
        for (int i = 0; i &lt; n; i++) {
            cin &gt;&gt; str[i];
        }
        cout &lt;&lt; findPrefix(str) &lt;&lt; endl;
    }
    return 0;
}
`**Python Implementation:**

`def longest_common_prefix(strs):
    if not strs:
        return "-1"
    strs.sort()
    first, last = strs[0], strs[-1]
    i = 0
    while i &lt; len(first) and i &lt; len(last) and first[i] == last[i]:
        i += 1
    prefix = first[:i]
    return prefix if prefix != "" else "-1"

if __name__ == "__main__":
    t = int(input())
    for _ in range(t):
        n = int(input())
        strs = input().split()
        print(longest_common_prefix(strs))
`**Idea:**

With vertical scanning, we examine the characters at each position (column) across all strings. For each character position:


Compare the character in the first string with those in the other strings.
If all strings have the same character, continue to the next position.
As soon as a mismatch is detected (or a string ends), return the substring from the beginning to that position.
**Complexity:**


The worst-case time complexity is O(n×m)O(n \times m)O(n×m), where nnn is the number of strings and mmm is the length of the common prefix.
**C++ Implementation:**

`#include &lt;iostream&gt;
#include &lt;vector&gt;
using namespace std;

string longestCommonPrefix(vector&lt;string&gt;&amp; strs) {
    if (strs.empty()) return "-1";
    for (int i = 0; i &lt; strs[0].size(); i++) {
        char c = strs[0][i];
        for (int j = 1; j &lt; strs.size(); j++) {
            if (i &gt;= strs[j].size() || strs[j][i] != c)
                return i == 0 ? "-1" : strs[0].substr(0, i);
        }
    }
    return strs[0] == "" ? "-1" : strs[0];
}

int main() {
    int t;
    cin &gt;&gt; t;
    while (t--) {
        int n;
        cin &gt;&gt; n;
        vector&lt;string&gt; strs(n);
        for (int i = 0; i &lt; n; i++) {
            cin &gt;&gt; strs[i];
        }
        cout &lt;&lt; longestCommonPrefix(strs) &lt;&lt; endl;
    }
    return 0;
}
`**Python Implementation:**

`def longest_common_prefix(strs):
    if not strs:
        return "-1"
    for i in range(len(strs[0])):
        char = strs[0][i]
        for s in strs[1:]:
            if i &gt;= len(s) or s[i] != char:
                return strs[0][:i] if i &gt; 0 else "-1"
    return strs[0] if strs[0] != "" else "-1"

if __name__ == "__main__":
    t = int(input())
    for _ in range(t):
        n = int(input())
        strs = input().split()
        print(longest_common_prefix(strs))
`**Idea:**

This approach divides the list of strings into two halves, finds the longest common prefix for each half recursively, and then merges the results by determining the common prefix of the two halves.

**Steps:**


If the list contains only one string, that string is the common prefix.
Divide the list into two halves.
Recursively compute the LCP for both halves.
Find the common prefix between the two halves using a helper function.
**Complexity:**


Although the worst-case time complexity is similar to vertical scanning (O(n×m)O(n \times m)O(n×m)), the divide and conquer approach makes use of recursion and provides a different perspective on solving the problem.
**C++ Implementation:**

`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;
using namespace std;

string commonPrefix(const string&amp; left, const string&amp; right) {
    int minLen = min(left.size(), right.size());
    for (int i = 0; i &lt; minLen; i++) {
        if (left[i] != right[i])
            return left.substr(0, i);
    }
    return left.substr(0, minLen);
}

string longestCommonPrefixUtil(vector&lt;string&gt;&amp; strs, int l, int r) {
    if (l == r)
        return strs[l];
    else {
        int mid = (l + r) / 2;
        string lcpLeft = longestCommonPrefixUtil(strs, l, mid);
        string lcpRight = longestCommonPrefixUtil(strs, mid + 1, r);
        return commonPrefix(lcpLeft, lcpRight);
    }
}

int main() {
    int t;
    cin &gt;&gt; t;
    while (t--) {
        int n;
        cin &gt;&gt; n;
        vector&lt;string&gt; strs(n);
        for (int i = 0; i &lt; n; i++) {
            cin &gt;&gt; strs[i];
        }
        string result = longestCommonPrefixUtil(strs, 0, n - 1);
        cout &lt;&lt; (result == "" ? "-1" : result) &lt;&lt; endl;
    }
    return 0;
}
`**Python Implementation:**

`def common_prefix(left, right):
    min_len = min(len(left), len(right))
    for i in range(min_len):
        if left[i] != right[i]:
            return left[:i]
    return left[:min_len]

def longest_common_prefix_divide(strs, l, r):
    if l == r:
        return strs[l]
    else:
        mid = (l + r) // 2
        lcp_left = longest_common_prefix_divide(strs, l, mid)
        lcp_right = longest_common_prefix_divide(strs, mid + 1, r)
        return common_prefix(lcp_left, lcp_right)

def longest_common_prefix(strs):
    if not strs:
        return "-1"
    prefix = longest_common_prefix_divide(strs, 0, len(strs) - 1)
    return prefix if prefix != "" else "-1"

if __name__ == "__main__":
    t = int(input())
    for _ in range(t):
        n = int(input())
        strs = input().split()
        print(longest_common_prefix(strs))
`
